class ScienceSimulation {
    constructor(container, initialInputs) {
        this.container = container;
        this.canvas = document.createElement('canvas');
        this.ctx = this.canvas.getContext('2d');
        this.container.appendChild(this.canvas);
        this.resize();
        window.addEventListener('resize', () => this.resize());
    }

    resize() {
        this.canvas.width = this.container.clientWidth * window.devicePixelRatio;
        this.canvas.height = this.container.clientHeight * window.devicePixelRatio;
        this.canvas.style.width = `${this.container.clientWidth}px`;
        this.canvas.style.height = `${this.container.clientHeight}px`;
    }

    nmToRGB(wavelength) {
        let r, g, b, factor;
        if (wavelength >= 380 && wavelength < 440) {
            r = -(wavelength - 440) / (440 - 380); g = 0.0; b = 1.0;
        } else if (wavelength >= 440 && wavelength < 490) {
            r = 0.0; g = (wavelength - 440) / (490 - 440); b = 1.0;
        } else if (wavelength >= 490 && wavelength < 510) {
            r = 0.0; g = 1.0; b = -(wavelength - 510) / (510 - 490);
        } else if (wavelength >= 510 && wavelength < 580) {
            r = (wavelength - 510) / (580 - 510); g = 1.0; b = 0.0;
        } else if (wavelength >= 580 && wavelength < 645) {
            r = 1.0; g = -(wavelength - 645) / (645 - 580); b = 0.0;
        } else if (wavelength >= 645 && wavelength <= 750) {
            r = 1.0; g = 0.0; b = 0.0;
        } else {
            r = 0.0; g = 0.0; b = 0.0;
        }
        if (wavelength >= 380 && wavelength < 420) factor = 0.3 + 0.7 * (wavelength - 380) / (420 - 380);
        else if (wavelength >= 420 && wavelength < 701) factor = 1.0;
        else if (wavelength >= 701 && wavelength <= 750) factor = 0.3 + 0.7 * (750 - wavelength) / (750 - 701);
        else factor = 0.0;
        return `rgb(${Math.round(r * 255 * factor)},${Math.round(g * 255 * factor)},${Math.round(b * 255 * factor)})`;
    }

    getSteps(inputs) {
        const fringeSpacing = (inputs.wavelength * 1e-9 * inputs.distanceToScreen) / (inputs.slitSeparation * 1e-6);
        return [
            {
                title: "Experimental Setup",
                description: `A monochromatic light source with $\\lambda = ${inputs.wavelength}$ nm shines on two slits separated by $d = ${inputs.slitSeparation}$ µm. The screen is placed $L = ${inputs.distanceToScreen}$ m away.`
            },
            {
                title: "Wave Propagation",
                description: "According to Huygens' Principle, each slit acts as a source of spherical wavelets. These waves overlap in the space between the slits and the screen."
            },
            {
                title: "Path Difference",
                description: "At any point on the screen, the light from the two slits travels different distances. The path difference $\\Delta L \\approx d \\sin \\theta$ determines whether the waves arrive in phase or out of phase."
            },
            {
                title: "Interference Pattern",
                description: `The fringe spacing (distance between bright spots) is approximately $\\Delta y = \\frac{\\lambda L}{d} \\approx ${(fringeSpacing * 1000).toFixed(3)}$ mm. The overall intensity is modulated by the single-slit diffraction envelope.`
            }
        ];
    }

    render(inputs, stepIndex) {
        const { ctx, canvas } = this;
        const w = canvas.width;
        const h = canvas.height;
        const color = this.nmToRGB(inputs.wavelength);

        ctx.fillStyle = '#0f172a';
        ctx.fillRect(0, 0, w, h);

        const margin = 50;
        const simWidth = w * 0.6;
        const screenX = simWidth;
        const slitX = 100;
        const centerY = h / 2;

        // Draw Slits
        ctx.strokeStyle = '#94a3b8';
        ctx.lineWidth = 4;
        ctx.beginPath();
        ctx.moveTo(slitX, 0); ctx.lineTo(slitX, centerY - (inputs.slitSeparation * 2) - 10);
        ctx.moveTo(slitX, centerY - (inputs.slitSeparation * 2) + 10); ctx.lineTo(slitX, centerY + (inputs.slitSeparation * 2) - 10);
        ctx.moveTo(slitX, centerY + (inputs.slitSeparation * 2) + 10); ctx.lineTo(slitX, h);
        ctx.stroke();

        // Draw Waves
        if (stepIndex >= 1) {
            ctx.save();
            ctx.globalAlpha = 0.4;
            ctx.strokeStyle = color;
            ctx.lineWidth = 1;
            const slit1Y = centerY - (inputs.slitSeparation * 2);
            const slit2Y = centerY + (inputs.slitSeparation * 2);

            for (let r = 20; r < (screenX - slitX); r += 20) {
                ctx.beginPath();
                ctx.arc(slit1Y > 0 ? slitX : -1000, slit1Y, r, -Math.PI/2, Math.PI/2);
                ctx.stroke();
                ctx.beginPath();
                ctx.arc(slit2Y > 0 ? slitX : -1000, slit2Y, r, -Math.PI/2, Math.PI/2);
                ctx.stroke();
            }
            ctx.restore();
        }

        // Draw Screen and Intensity
        if (stepIndex >= 3) {
            const intensityWidth = w - screenX - margin;
            const lambda = inputs.wavelength * 1e-9;
            const d = inputs.slitSeparation * 1e-6;
            const a = inputs.slitWidth * 1e-6;
            const L = inputs.distanceToScreen;

            ctx.beginPath();
            ctx.strokeStyle = '#ffffff';
            ctx.moveTo(screenX, 0); ctx.lineTo(screenX, h);
            ctx.stroke();

            ctx.beginPath();
            ctx.moveTo(screenX, centerY);

            for (let y = -h/2; y < h/2; y += 1) {
                const theta = Math.atan(y / (L * 500)); // Scaled for visual
                const beta = (Math.PI * a * Math.sin(theta)) / lambda;
                const alpha = (Math.PI * d * Math.sin(theta)) / lambda;

                const diffraction = beta === 0 ? 1 : Math.pow(Math.sin(beta) / beta, 2);
                const interference = Math.pow(Math.cos(alpha), 2);
                const intensity = diffraction * interference;

                const plotX = screenX + 5 + intensity * intensityWidth;
                ctx.lineTo(plotX, centerY + y);

                // Draw fringe on screen
                ctx.fillStyle = color;
                ctx.globalAlpha = intensity;
                ctx.fillRect(screenX - 20, centerY + y, 20, 1);
            }
            ctx.globalAlpha = 1.0;
            ctx.strokeStyle = color;
            ctx.lineWidth = 2;
            ctx.stroke();
        }

        // Labels
        ctx.fillStyle = '#f8fafc';
        ctx.font = '16px Inter, sans-serif';
        ctx.fillText('Source', 20, 30);
        ctx.fillText('Slits', slitX - 20, 30);
        ctx.fillText('Screen', screenX - 60, 30);
        if (stepIndex >= 3) ctx.fillText('Intensity Profile', screenX + 20, 30);
    }
}
